#include<bits/stdc++.h>
using namespace std;
const int M=20005;
int t[M],g[M];
int n,a[105],ans,maxx;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        g[a[i]]=1;
    }
    for(int i=1;i<n;i++)
    {
        for(int j=i+1;j<=n;j++)
        {
            t[a[i]+a[j]]++;
            maxx=max(maxx,a[i]+a[j]);
        }
    }
    for(int i=1;i<=maxx;i++)
    {
        if(t[i]>0&&g[i]) ans++;
    }
    cout<<ans;
    return 0;
}
